const states = ['ENTER','SIT','ORDER','EAT','PAY','LEAVE'];
const gamma = 0.8;

// Build transition matrix (simple chain)
const T = states.map((_,i) => states.map((_,j) => j===i+1 ? 1.0 : 0));

// Compute SR: M = I + γT + γ²T² + ...
function matMul(A,B) {
  return A.map((row,i) => B[0].map((_,j) => row.reduce((s,_,k) => s+A[i][k]*B[k][j],0)));
}
function matAdd(A,B) { return A.map((r,i) => r.map((v,j) => v+B[i][j])); }
function matScale(A,s) { return A.map(r => r.map(v => v*s)); }

let M = states.map((_,i) => states.map((_,j) => i===j?1:0)); // Identity
let Tk = T.map(r=>[...r]); // T^k starts at T^1
for(let k=1; k<=10; k++) {
  M = matAdd(M, matScale(Tk, Math.pow(gamma,k)));
  Tk = matMul(Tk, T);
}

// Display SR from ENTER state
const fromEnter = M[0];
const maxVal = Math.max(...fromEnter);
const bar = (v) => '█'.repeat(Math.round(v/maxVal*20));
return states.map((s,i) => `${s.padEnd(7)} ${bar(fromEnter[i])} ${fromEnter[i].toFixed(2)}`).join('\n');

const scenarios = [
  { name: 'Toy (100 states)', S: 100, K: 14, d: 16 },
  { name: 'Small (1K states)', S: 1000, K: 14, d: 32 },
  { name: 'Medium (10K states)', S: 10000, K: 14, d: 64 },
  { name: 'Real-world (100K states)', S: 100000, K: 14, d: 128 },
];

return scenarios.map(s => {
  const flat = s.S * s.S;
  const factored = s.K * s.d * s.d;
  const ratio = (flat / factored).toFixed(0);
  return `${s.name}:\n  Flat SR: ${flat.toLocaleString()} params\n  Factored: ${factored.toLocaleString()} params\n  Compression: ${ratio}x\n`;
}).join('\n');

// A branching narrative with a critical hub event
const events = ['Setup','Clue_A','Clue_B','MURDER','Red_Herring','Investigation','Reveal','Arrest'];
const transitions = [
  [0,1],[0,2],[1,3],[2,3],[3,4],[3,5],[4,4],[5,6],[6,7]
];
const gamma = 0.7;
const n = events.length;

// Build T
const T = Array.from({length:n}, ()=>Array(n).fill(0));
for(const [i,j] of transitions) {
  // Count outgoing edges for normalization
  const outCount = transitions.filter(([f])=>f===i).length;
  T[i][j] = 1/outCount;
}

// SR via power series
let M = Array.from({length:n},(_,i)=>Array.from({length:n},(_,j)=>i===j?1:0));
let Tk = T.map(r=>[...r]);
for(let k=1;k<=20;k++) {
  for(let i=0;i<n;i++) for(let j=0;j<n;j++) M[i][j]+=Math.pow(gamma,k)*Tk[i][j];
  const nT=Array.from({length:n},()=>Array(n).fill(0));
  for(let i=0;i<n;i++) for(let j=0;j<n;j++) for(let k2=0;k2<n;k2++) nT[i][j]+=Tk[i][k2]*T[k2][j];
  Tk=nT;
}

// Centrality = column sum of M (how much each state is visited from all starts)
const centrality = events.map((_,j) => M.reduce((s,row)=>s+row[j],0));
const maxC = Math.max(...centrality);
const bar = v => '█'.repeat(Math.round(v/maxC*25));

return events.map((e,i) => 
  `${e.padEnd(15)} ${bar(centrality[i])} ${centrality[i].toFixed(2)}`
).join('\n') + '\n\n→ MURDER has highest centrality: it\'s the narrative hub!';
